/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications.
 * Currently focused on email settings — designed to be extensible
 * when additional channels are added later.
 */

import type { NotificationType } from './notification.js';

/**
 * Email delivery frequency.
 * - 'immediate': Send emails as events occur.
 * - 'daily_digest': Batch into a daily summary (future implementation).
 * - 'weekly_digest': Batch into a weekly summary (future implementation).
 */
export type EmailFrequency = 'immediate' | 'daily_digest' | 'weekly_digest';

/**
 * Per-category email subscription settings.
 * Each notification type can be independently enabled or disabled.
 */
export interface EmailCategoryPreferences {
  order_confirmation: boolean;
  order_status_update: boolean;
  welcome: boolean;
  account_updated: boolean;
}

/**
 * Email-specific notification preferences.
 */
export interface EmailPreferences {
  enabled: boolean;
  frequency: EmailFrequency;
  categories: EmailCategoryPreferences;
}

/**
 * Full user notification preferences record.
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for creating user preferences.
 * All fields are optional — defaults are applied by the service.
 */
export interface CreatePreferencesInput {
  userId: string;
  email?: Partial<EmailPreferences & { categories?: Partial<EmailCategoryPreferences> }>;
}

/**
 * Input for updating user preferences.
 */
export interface UpdatePreferencesInput {
  email?: Partial<EmailPreferences & { categories?: Partial<EmailCategoryPreferences> }>;
}

/**
 * Returns default email preferences — all notifications enabled, immediate delivery.
 */
export function defaultEmailPreferences(): EmailPreferences {
  return {
    enabled: true,
    frequency: 'immediate',
    categories: {
      order_confirmation: true,
      order_status_update: true,
      welcome: true,
      account_updated: true,
    },
  };
}

/**
 * Check if a specific notification type is enabled in email preferences.
 */
export function isEmailCategoryEnabled(
  prefs: EmailPreferences,
  type: NotificationType,
): boolean {
  if (!prefs.enabled) return false;
  return prefs.categories[type] ?? true;
}

/**
 * Repository for user notification preferences.
 *
 * Follows the existing Repository pattern — extends BaseRepository
 * for standard CRUD, adds a lookup-by-userId method.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import { BaseRepository } from './base.repository.js';
import type { UserPreferences } from '../models/user-preferences.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    return {
      id: record.id as string,
      userId: record.userId as string,
      email: record.email as UserPreferences['email'],
      createdAt: new Date(record.createdAt as string),
      updatedAt: new Date(record.updatedAt as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      email: entity.email as unknown as DatabaseRecord['email'],
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const all = this.findAll((p) => p.userId === userId);
    return all[0];
  }
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for preferences and a shouldSend() check
 * that the NotificationService uses before dispatching notifications.
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type {
  UserPreferences,
  CreatePreferencesInput,
  UpdatePreferencesInput,
} from '../models/user-preferences.js';
import { defaultEmailPreferences, isEmailCategoryEnabled } from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private repository: PreferencesRepository) {}

  /**
   * Get preferences for a user. Returns undefined if none are set.
   */
  getByUserId(userId: string): UserPreferences | undefined {
    return this.repository.findByUserId(userId);
  }

  /**
   * Create preferences for a user.
   * Merges provided input with defaults so all fields are populated.
   */
  create(input: CreatePreferencesInput): UserPreferences {
    const existing = this.repository.findByUserId(input.userId);
    if (existing) {
      throw new Error(`Preferences already exist for user: ${input.userId}`);
    }

    const defaults = defaultEmailPreferences();
    const emailInput = input.email ?? {};
    const categoriesInput = emailInput.categories ?? {};

    const prefs: UserPreferences = {
      id: generatePreferencesId(),
      userId: input.userId,
      email: {
        enabled: emailInput.enabled ?? defaults.enabled,
        frequency: emailInput.frequency ?? defaults.frequency,
        categories: {
          order_confirmation: categoriesInput.order_confirmation ?? defaults.categories.order_confirmation,
          order_status_update: categoriesInput.order_status_update ?? defaults.categories.order_status_update,
          welcome: categoriesInput.welcome ?? defaults.categories.welcome,
          account_updated: categoriesInput.account_updated ?? defaults.categories.account_updated,
        },
      },
      createdAt: new Date(),
      updatedAt: new Date(),
    };

    this.logger.info(`Created preferences for user: ${input.userId}`);
    return this.repository.save(prefs);
  }

  /**
   * Update existing preferences for a user.
   * Merges updates into the current preferences.
   */
  update(userId: string, input: UpdatePreferencesInput): UserPreferences {
    const existing = this.repository.findByUserId(userId);
    if (!existing) {
      throw new Error(`No preferences found for user: ${userId}`);
    }

    const emailInput = input.email ?? {};
    const categoriesInput = emailInput.categories ?? {};

    const updated: UserPreferences = {
      ...existing,
      email: {
        enabled: emailInput.enabled ?? existing.email.enabled,
        frequency: emailInput.frequency ?? existing.email.frequency,
        categories: {
          order_confirmation: categoriesInput.order_confirmation ?? existing.email.categories.order_confirmation,
          order_status_update: categoriesInput.order_status_update ?? existing.email.categories.order_status_update,
          welcome: categoriesInput.welcome ?? existing.email.categories.welcome,
          account_updated: categoriesInput.account_updated ?? existing.email.categories.account_updated,
        },
      },
      updatedAt: new Date(),
    };

    this.logger.info(`Updated preferences for user: ${userId}`);
    return this.repository.update(existing.id, updated);
  }

  /**
   * Delete preferences for a user (resets to defaults).
   */
  delete(userId: string): boolean {
    const existing = this.repository.findByUserId(userId);
    if (!existing) return false;
    this.logger.info(`Deleted preferences for user: ${userId}`);
    return this.repository.delete(existing.id);
  }

  /**
   * Check whether a notification should be sent to a user via email.
   * Returns true if:
   * - No preferences are set (default: all enabled)
   * - Email is enabled AND the specific category is enabled
   */
  shouldSendEmail(userId: string, type: NotificationType): boolean {
    const prefs = this.repository.findByUserId(userId);
    if (!prefs) return true; // No preferences = default to all enabled
    return isEmailCategoryEnabled(prefs.email, type);
  }
}

