/**
 * Send a notification through all registered adapters.
 * Each adapter attempts delivery independently — one failure does not block others.
 * Checks user preferences before sending — if the user has opted out, the
 * notification is skipped for that adapter's channel.
 */
async send(payload: NotificationPayload): Promise<Notification[]> {
  this.logger.info(`Sending ${payload.type} notification to ${payload.recipient}`);

  // Check user preferences if a preferences service is configured
  const userId = payload.metadata?.userId as string | undefined;
  if (userId && this.preferencesService) {
    if (!this.preferencesService.shouldSendEmail(userId, payload.type)) {
      this.logger.info(
        `Notification ${payload.type} suppressed for user ${userId} (preferences)`,
      );
      return [];
