import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import type { OrderCreatedEvent, UserCreatedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let db: Database;
  let repository: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repository = new PreferencesRepository(db);
    service = new PreferencesService(repository);
    resetPreferencesIdCounter();
  });

  describe('create', () => {
    it('should create preferences with defaults', () => {
      const prefs = service.create({ userId: 'user-1' });

      expect(prefs.userId).toBe('user-1');
      expect(prefs.id).toBe('pref-0001');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.categories.order_confirmation).toBe(true);
      expect(prefs.email.categories.order_status_update).toBe(true);
      expect(prefs.email.categories.welcome).toBe(true);
      expect(prefs.email.categories.account_updated).toBe(true);
    });

    it('should create preferences with custom email settings', () => {
      const prefs = service.create({
        userId: 'user-1',
        email: {
          enabled: true,
          frequency: 'daily_digest',
          categories: { order_status_update: false },
        },
      });

      expect(prefs.email.frequency).toBe('daily_digest');
      expect(prefs.email.categories.order_status_update).toBe(false);
      expect(prefs.email.categories.order_confirmation).toBe(true);
    });

    it('should create preferences with email disabled', () => {
      const prefs = service.create({
        userId: 'user-1',
        email: { enabled: false },
      });

      expect(prefs.email.enabled).toBe(false);
    });

    it('should throw if preferences already exist for user', () => {
      service.create({ userId: 'user-1' });
      expect(() => service.create({ userId: 'user-1' })).toThrow(
        'Preferences already exist for user: user-1',
      );
    });

    it('should generate sequential IDs', () => {
      const p1 = service.create({ userId: 'user-1' });
      const p2 = service.create({ userId: 'user-2' });

      expect(p1.id).toBe('pref-0001');
      expect(p2.id).toBe('pref-0002');
    });
  });

  describe('getByUserId', () => {
    it('should return preferences for a user', () => {
      service.create({ userId: 'user-1' });

      const result = service.getByUserId('user-1');
      expect(result).toBeDefined();
      expect(result!.userId).toBe('user-1');
    });

    it('should return undefined when no preferences exist', () => {
      expect(service.getByUserId('user-999')).toBeUndefined();
    });
  });

  describe('update', () => {
    it('should update email enabled flag', () => {
      service.create({ userId: 'user-1' });

      const updated = service.update('user-1', {
        email: { enabled: false },
      });

      expect(updated.email.enabled).toBe(false);
      expect(updated.email.categories.order_confirmation).toBe(true);
    });

    it('should update specific categories', () => {
      service.create({ userId: 'user-1' });

      const updated = service.update('user-1', {
        email: { categories: { welcome: false, account_updated: false } },
      });

      expect(updated.email.categories.welcome).toBe(false);
      expect(updated.email.categories.account_updated).toBe(false);
      expect(updated.email.categories.order_confirmation).toBe(true);
      expect(updated.email.categories.order_status_update).toBe(true);
    });

    it('should update frequency', () => {
      service.create({ userId: 'user-1' });

      const updated = service.update('user-1', {
        email: { frequency: 'weekly_digest' },
      });

      expect(updated.email.frequency).toBe('weekly_digest');
    });

    it('should throw if no preferences exist', () => {
      expect(() => service.update('user-999', { email: { enabled: false } })).toThrow(
        'No preferences found for user: user-999',
      );
    });

    it('should update the updatedAt timestamp', () => {
      const created = service.create({ userId: 'user-1' });
      const createdTime = created.updatedAt.getTime();

      // Small delay to ensure timestamp difference
      const updated = service.update('user-1', { email: { enabled: false } });
      expect(updated.updatedAt.getTime()).toBeGreaterThanOrEqual(createdTime);
    });
  });

  describe('delete', () => {
    it('should delete existing preferences', () => {
      service.create({ userId: 'user-1' });

      expect(service.delete('user-1')).toBe(true);
      expect(service.getByUserId('user-1')).toBeUndefined();
    });

    it('should return false when no preferences exist', () => {
      expect(service.delete('user-999')).toBe(false);
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true when no preferences are set (default behavior)', () => {
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return true when email is enabled and category is enabled', () => {
      service.create({ userId: 'user-1' });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return false when email is disabled globally', () => {
      service.create({ userId: 'user-1', email: { enabled: false } });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(false);
    });

    it('should return false for a disabled category', () => {
      service.create({
        userId: 'user-1',
        email: { categories: { order_status_update: false } },
      });

      expect(service.shouldSendEmail('user-1', 'order_status_update')).toBe(false);
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
    });

    it('should reflect updated preferences', () => {
      service.create({ userId: 'user-1' });

      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(true);

      service.update('user-1', { email: { categories: { welcome: false } } });

      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(false);
    });

    it('should return true after preferences are deleted (back to defaults)', () => {
      service.create({ userId: 'user-1', email: { enabled: false } });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);

      service.delete('user-1');

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
    });
  });
});

describe('NotificationService with preferences', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let preferencesService: PreferencesService;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    const repository = new PreferencesRepository(db);
    preferencesService = new PreferencesService(repository);
    notificationService.setPreferencesService(preferencesService);
    resetNotificationIdCounter();
    resetPreferencesIdCounter();
  });

  it('should send notification when no preferences exist', async () => {
    const event: UserCreatedEvent = {
      type: 'user:created',
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(notificationService.getNotificationCount()).toBe(1);
  });

  it('should suppress notification when user has disabled the category', async () => {
    preferencesService.create({
      userId: 'user-1',
      email: { categories: { order_confirmation: false } },
    });

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(notificationService.getNotificationCount()).toBe(0);
  });

  it('should suppress all notifications when email is globally disabled', async () => {
    preferencesService.create({
      userId: 'user-1',
      email: { enabled: false },
    });

    const event: UserCreatedEvent = {
      type: 'user:created',
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(notificationService.getNotificationCount()).toBe(0);
  });

  it('should send notification when category is enabled in preferences', async () => {
    preferencesService.create({
      userId: 'user-1',
      email: {
        categories: { order_confirmation: false, welcome: true },
      },
    });

    const event: UserCreatedEvent = {
      type: 'user:created',
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(notificationService.getNotificationCount()).toBe(1);
  });

  it('should work without preferences service (backward compatible)', async () => {
    const plainEventBus = new EventBus();
    const plainService = new NotificationService(plainEventBus);
    resetNotificationIdCounter();

    const event: UserCreatedEvent = {
      type: 'user:created',
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await plainEventBus.emit(event);

    expect(plainService.getNotificationCount()).toBe(1);
  });
});

